// // This module converts a 4-bit input to a 2-bit output based on specific ranges.
// The output is set to 11 when the input is 4 or less, 10 for inputs between 5 and 8,
// 01 for inputs between 9 and 12, and 00 for inputs greater than 12.
module top_module(
    input [3:0] data_in,
    output reg [1:0] data_out  // Change wire to reg
);always @* begin
        if (data_in <= 4) begin
            data_out = 2'b00;
        end else if (data_in <= 8) begin
            data_out = 2'b01;
        end else if (data_in <= 12) begin
            data_out = 2'b10;
        end else begin
            data_out = 2'b11;
        end
    end

endmodule

